request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?contextType ?contextName ?prop ?valueName WHERE {
  {
    SELECT DISTINCT "Observatory" AS ?contextType ?contextName WHERE {
      ?context rdf:type ?contextTypeRaw .
      FILTER(?contextTypeRaw IN (vocab:package, vocab:block, vocab:view)).
      ?context vocab:NamedElement_name ?contextName .
      FILTER(CONTAINS(LCASE(?contextName), LCASE("observatory")))
      FILTER(CONTAINS(LCASE(STR(?contextName)), LCASE("execut")) || CONTAINS(LCASE(STR(?contextName)), LCASE("software")))
    }
  }

  ?exec vocab:NamedElement_name ?execName .
  FILTER(CONTAINS(LCASE(STR(?execName)), LCASE("execut")) && CONTAINS(LCASE(STR(?execName)), LCASE("software")))

  ?exec (vocab:Element_owner|^vocab:Element_ownedElement)+ ?context .

  ?exec ?prop ?value .
  OPTIONAL { ?value vocab:NamedElement_name ?valueName }
}
LIMIT 25
